import React from "react";
import styled from "styled-components";
import { FlexWrapper } from "../../../components/FlexWrapper";
import { SectionTitle } from "../../../components/SectionTitle";
import { Skill } from "./skill/Skill";

export const Skills = () => {
    return (
        <StuledSkills>
            <SectionTitle>My Skills</SectionTitle>
            <FlexWrapper>
                <Skill iconId={"htmlIcon"} title={"HTML 5"} text={"Describe HTML 5"} />
                <Skill iconId={"cssIcon"} title={"CSS 3"} text={"Describe CSS 3"} />
                <Skill iconId={"jsIcon"} title={"JS"} text={"Describe JS"} />
                <Skill iconId={"htmlIcon"} title={"HTML5"} text={"Describe Describe Describe Describe Describe"} />
                <Skill iconId={"htmlIcon"} title={"HTML5 HTML5 HTML5"} text={"Describe"} />
                <Skill iconId={"htmlIcon"} title={"HTML5"} text={"Describe"} />
            </FlexWrapper>
        </StuledSkills>
    )
}


const StuledSkills = styled.section`
    background-color: #928486;
    min-height: 100vh;
`
